  1→/**
  2→ * Codebase conventions detector
  3→ *
  4→ * Deterministic detection of observable codebase patterns.
  5→ * No AI/ML — just file scanning and pattern matching.
  6→ */
  7→
  8→import { readdir, stat } from "fs/promises";
  9→import { join, extname, basename } from "path";
 10→import { fileExists, readFile, writeFile, ensureDir } from "./fs.js";
 11→
 12→/** Path to conventions file */
 13→export const CONVENTIONS_PATH = ".sequant/conventions.json";
 14→
 15→/**
 16→ * A single detected convention
 17→ */
 18→export interface Convention {
 19→  /** Machine-readable key */
 20→  key: string;
 21→  /** Human-readable label */
 22→  label: string;
 23→  /** Detected value */
 24→  value: string;
 25→  /** How it was detected */
 26→  source: "detected" | "manual";
 27→  /** What evidence triggered detection */
 28→  evidence?: string;
 29→}
 30→
 31→/**
 32→ * Full conventions file schema
 33→ */
 34→export interface ConventionsFile {
 35→  /** Auto-detected conventions */
 36→  detected: Record<string, string>;
 37→  /** User-provided overrides */
 38→  manual: Record<string, string>;
 39→  /** When detection was last run */
 40→  detectedAt: string;
 41→}
 42→
 43→/** Directories to skip during scanning */
 44→const SKIP_DIRS = new Set([
 45→  "node_modules",
 46→  ".git",
 47→  "dist",
 48→  "build",
 49→  ".next",
 50→  ".nuxt",
 51→  ".output",
 52→  "__pycache__",
 53→  "target",
 54→  ".claude",
 55→  ".sequant",
 56→  "coverage",
 57→  ".turbo",
 58→  ".cache",
 59→  "vendor",
 60→]);
 61→
 62→/**
 63→ * Collect source files up to a limit, skipping irrelevant directories
 64→ */
 65→async function collectFiles(
 66→  dir: string,
 67→  extensions: Set<string>,
 68→  maxFiles: number,
 69→  depth = 0,
 70→): Promise<string[]> {
 71→  if (depth > 5) return [];
 72→  const results: string[] = [];
 73→
 74→  let entries;
 75→  try {
 76→    entries = await readdir(dir, { withFileTypes: true });
 77→  } catch {
 78→    return results;
 79→  }
 80→
 81→  for (const entry of entries) {
 82→    if (results.length >= maxFiles) break;
 83→
 84→    if (entry.isDirectory()) {
 85→      if (SKIP_DIRS.has(entry.name) || entry.name.startsWith(".")) continue;
 86→      const sub = await collectFiles(
 87→        join(dir, entry.name),
 88→        extensions,
 89→        maxFiles - results.length,
 90→        depth + 1,
 91→      );
 92→      results.push(...sub);
 93→    } else if (entry.isFile() && extensions.has(extname(entry.name))) {
 94→      results.push(join(dir, entry.name));
 95→    }
 96→  }
 97→
 98→  return results;
 99→}
100→
101→/**
102→ * Count occurrences of a pattern in file contents
103→ */
104→async function countPattern(
105→  files: string[],
106→  pattern: RegExp,
107→  maxFiles = 50,
108→): Promise<number> {
109→  let count = 0;
110→  for (const file of files.slice(0, maxFiles)) {
111→    try {
112→      const content = await readFile(file);
113→      const matches = content.match(pattern);
114→      if (matches) count += matches.length;
115→    } catch {
116→      // Skip unreadable files
117→    }
118→  }
119→  return count;
120→}
121→
122→/**
123→ * Detect test file naming convention
124→ */
125→async function detectTestPattern(root: string): Promise<Convention | null> {
126→  const testFiles = await collectFiles(
127→    root,
128→    new Set([".ts", ".tsx", ".js", ".jsx"]),
129→    500,
130→  );
131→
132→  const dotTest = testFiles.filter((f) => /\.test\.[jt]sx?$/.test(f));
133→  const dotSpec = testFiles.filter((f) => /\.spec\.[jt]sx?$/.test(f));
134→  const underscoreTests = testFiles.filter((f) => f.includes("__tests__/"));
135→
136→  if (
137→    dotTest.length === 0 &&
138→    dotSpec.length === 0 &&
139→    underscoreTests.length === 0
140→  ) {
141→    return null;
142→  }
143→
144→  let value: string;
145→  let evidence: string;
146→
147→  if (
148→    dotTest.length >= dotSpec.length &&
149→    dotTest.length >= underscoreTests.length
150→  ) {
151→    value = "*.test.ts";
152→    evidence = `${dotTest.length} .test.* files found`;
153→  } else if (dotSpec.length >= underscoreTests.length) {
154→    value = "*.spec.ts";
155→    evidence = `${dotSpec.length} .spec.* files found`;
156→  } else {
157→    value = "__tests__/";
158→    evidence = `${underscoreTests.length} files in __tests__/ directories`;
159→  }
160→
161→  return {
162→    key: "testFilePattern",
163→    label: "Test file pattern",
164→    value,
165→    source: "detected",
166→    evidence,
167→  };
168→}
169→
170→/**
171→ * Detect export style preference (named vs default)
172→ */
173→async function detectExportStyle(root: string): Promise<Convention | null> {
174→  const srcDir = join(root, "src");
175→  const searchDir = (await fileExists(srcDir)) ? srcDir : root;
176→  const files = await collectFiles(
177→    searchDir,
178→    new Set([".ts", ".tsx", ".js", ".jsx"]),
179→    100,
180→  );
181→
182→  if (files.length === 0) return null;
183→
184→  const defaultExports = await countPattern(files, /export\s+default\b/g, 50);
185→  const namedExports = await countPattern(
186→    files,
187→    /export\s+(?:async\s+)?(?:function|class|const|let|interface|type|enum)\b/g,
188→    50,
189→  );
190→
191→  if (defaultExports === 0 && namedExports === 0) return null;
192→
193→  const total = defaultExports + namedExports;
194→  const namedRatio = namedExports / total;
195→
196→  let value: string;
197→  if (namedRatio > 0.7) {
198→    value = "named";
199→  } else if (namedRatio < 0.3) {
200→    value = "default";
201→  } else {
202→    value = "mixed";
203→  }
204→
205→  return {
206→    key: "exportStyle",
207→    label: "Export style",
208→    value,
209→    source: "detected",
210→    evidence: `${namedExports} named, ${defaultExports} default exports`,
211→  };
212→}
213→
214→/**
215→ * Detect async pattern preference
216→ */
217→async function detectAsyncPattern(root: string): Promise<Convention | null> {
218→  const srcDir = join(root, "src");
219→  const searchDir = (await fileExists(srcDir)) ? srcDir : root;
220→  const files = await collectFiles(
221→    searchDir,
222→    new Set([".ts", ".tsx", ".js", ".jsx"]),
223→    100,
224→  );
225→
226→  if (files.length === 0) return null;
227→
228→  const awaitCount = await countPattern(files, /\bawait\b/g, 50);
229→  const thenCount = await countPattern(files, /\.then\s*\(/g, 50);
230→
231→  if (awaitCount === 0 && thenCount === 0) return null;
232→
233→  const total = awaitCount + thenCount;
234→  const awaitRatio = awaitCount / total;
235→
236→  let value: string;
237→  if (awaitRatio > 0.7) {
238→    value = "async/await";
239→  } else if (awaitRatio < 0.3) {
240→    value = "promise-chains";
241→  } else {
242→    value = "mixed";
243→  }
244→
245→  return {
246→    key: "asyncPattern",
247→    label: "Async pattern",
248→    value,
249→    source: "detected",
250→    evidence: `${awaitCount} await, ${thenCount} .then() usages`,
251→  };
252→}
253→
254→/**
255→ * Detect TypeScript strictness
256→ */
257→async function detectTypeScriptConfig(
258→  root: string,
259→): Promise<Convention | null> {
260→  const tsConfigPath = join(root, "tsconfig.json");
261→  if (!(await fileExists(tsConfigPath))) return null;
262→
263→  try {
264→    const content = await readFile(tsConfigPath);
265→    // Strip comments (single-line) for JSON parsing
266→    const stripped = content.replace(/\/\/.*$/gm, "");
267→    const config = JSON.parse(stripped);
268→    const strict = config?.compilerOptions?.strict;
269→
270→    return {
271→      key: "typescriptStrict",
272→      label: "TypeScript strict mode",
273→      value: strict ? "enabled" : "disabled",
274→      source: "detected",
275→      evidence: `tsconfig.json compilerOptions.strict = ${strict}`,
276→    };
277→  } catch {
278→    return null;
279→  }
280→}
281→
282→/**
283→ * Detect source directory structure
284→ */
285→async function detectSourceStructure(root: string): Promise<Convention | null> {
286→  const candidates = [
287→    { path: "src", label: "src/" },
288→    { path: "lib", label: "lib/" },
289→    { path: "app", label: "app/" },
290→    { path: "pages", label: "pages/" },
291→  ];
292→
293→  const found: string[] = [];
294→  for (const c of candidates) {
295→    const fullPath = join(root, c.path);
296→    try {
297→      const s = await stat(fullPath);
298→      if (s.isDirectory()) found.push(c.label);
299→    } catch {
300→      // doesn't exist
301→    }
302→  }
303→
304→  if (found.length === 0) return null;
305→
306→  return {
307→    key: "sourceStructure",
308→    label: "Source directory structure",
309→    value: found.join(", "),
310→    source: "detected",
311→    evidence: `Found directories: ${found.join(", ")}`,
312→  };
313→}
314→
315→/**
316→ * Detect package manager from lockfiles
317→ */
318→async function detectPackageManagerConvention(
319→  root: string,
320→): Promise<Convention | null> {
321→  const lockfiles: Array<{ file: string; manager: string }> = [
322→    { file: "bun.lockb", manager: "bun" },
323→    { file: "bun.lock", manager: "bun" },
324→    { file: "pnpm-lock.yaml", manager: "pnpm" },
325→    { file: "yarn.lock", manager: "yarn" },
326→    { file: "package-lock.json", manager: "npm" },
327→  ];
328→
329→  for (const { file, manager } of lockfiles) {
330→    if (await fileExists(join(root, file))) {
331→      return {
332→        key: "packageManager",
333→        label: "Package manager",
334→        value: manager,
335→        source: "detected",
336→        evidence: `Found ${file}`,
337→      };
338→    }
339→  }
340→
341→  return null;
342→}
343→
344→/**
345→ * Detect indentation style from source files
346→ */
347→async function detectIndentation(root: string): Promise<Convention | null> {
348→  const srcDir = join(root, "src");
349→  const searchDir = (await fileExists(srcDir)) ? srcDir : root;
350→  const files = await collectFiles(
351→    searchDir,
352→    new Set([".ts", ".tsx", ".js", ".jsx"]),
353→    30,
354→  );
355→
356→  if (files.length === 0) return null;
357→
358→  let twoSpace = 0;
359→  let fourSpace = 0;
360→  let tabs = 0;
361→
362→  for (const file of files.slice(0, 20)) {
363→    try {
364→      const content = await readFile(file);
365→      const lines = content.split("\n").slice(0, 50);
366→      for (const line of lines) {
367→        if (/^\t/.test(line)) tabs++;
368→        else if (/^  [^ ]/.test(line)) twoSpace++;
369→        else if (/^    [^ ]/.test(line)) fourSpace++;
370→      }
371→    } catch {
372→      // skip
373→    }
374→  }
375→
376→  const total = twoSpace + fourSpace + tabs;
377→  if (total === 0) return null;
378→
379→  let value: string;
380→  if (tabs > twoSpace && tabs > fourSpace) {
381→    value = "tabs";
382→  } else if (twoSpace >= fourSpace) {
383→    value = "2 spaces";
384→  } else {
385→    value = "4 spaces";
386→  }
387→
388→  return {
389→    key: "indentation",
390→    label: "Indentation",
391→    value,
392→    source: "detected",
393→    evidence: `${twoSpace} two-space, ${fourSpace} four-space, ${tabs} tab-indented lines`,
394→  };
395→}
396→
397→/**
398→ * Detect semicolon usage
399→ */
400→async function detectSemicolons(root: string): Promise<Convention | null> {
401→  const srcDir = join(root, "src");
402→  const searchDir = (await fileExists(srcDir)) ? srcDir : root;
403→  const files = await collectFiles(
404→    searchDir,
405→    new Set([".ts", ".tsx", ".js", ".jsx"]),
406→    30,
407→  );
408→
409→  if (files.length === 0) return null;
410→
411→  let withSemicolon = 0;
412→  let withoutSemicolon = 0;
413→
414→  for (const file of files.slice(0, 20)) {
415→    try {
416→      const content = await readFile(file);
417→      const lines = content.split("\n");
418→      for (const line of lines) {
419→        const trimmed = line.trim();
420→        // Skip empty lines, comments, opening/closing brackets
421→        if (
422→          !trimmed ||
423→          trimmed.startsWith("//") ||
424→          trimmed.startsWith("/*") ||
425→          trimmed.startsWith("*") ||
426→          /^[{}()\[\]]$/.test(trimmed) ||
427→          /^import\s/.test(trimmed) ||
428→          /^export\s/.test(trimmed)
429→        )
430→          continue;
431→
432→        if (trimmed.endsWith(";")) withSemicolon++;
433→        else if (
434→          trimmed.endsWith(")") ||
435→          trimmed.endsWith('"') ||
436→          trimmed.endsWith("'") ||
437→          trimmed.endsWith("`") ||
438→          /\w$/.test(trimmed)
439→        )
440→          withoutSemicolon++;
441→      }
442→    } catch {
443→      // skip
444→    }
445→  }
446→
447→  const total = withSemicolon + withoutSemicolon;
448→  if (total === 0) return null;
449→
450→  const semiRatio = withSemicolon / total;
451→  const value =
452→    semiRatio > 0.6 ? "required" : semiRatio < 0.3 ? "omitted" : "mixed";
453→
454→  return {
455→    key: "semicolons",
456→    label: "Semicolons",
457→    value,
458→    source: "detected",
459→    evidence: `${withSemicolon} with, ${withoutSemicolon} without semicolons`,
460→  };
461→}
462→
463→/**
464→ * Detect component directory structure (for frontend projects)
465→ */
466→async function detectComponentStructure(
467→  root: string,
468→): Promise<Convention | null> {
469→  const candidates = [
470→    "src/components",
471→    "components",
472→    "src/app",
473→    "app",
474→    "src/pages",
475→    "pages",
476→  ];
477→
478→  for (const candidate of candidates) {
479→    const dirPath = join(root, candidate);
480→    try {
481→      const s = await stat(dirPath);
482→      if (s.isDirectory()) {
483→        return {
484→          key: "componentDir",
485→          label: "Component directory",
486→          value: candidate + "/",
487→          source: "detected",
488→          evidence: `Directory exists: ${candidate}/`,
489→        };
490→      }
491→    } catch {
492→      // doesn't exist
493→    }
494→  }
495→
496→  return null;
497→}
498→
499→/**
500→ * Run all convention detectors
501→ */
502→export async function detectConventions(
503→  projectRoot: string,
504→): Promise<Convention[]> {
505→  const detectors = [
506→    detectTestPattern,
507→    detectExportStyle,
508→    detectAsyncPattern,
509→    detectTypeScriptConfig,
510→    detectSourceStructure,
511→    detectPackageManagerConvention,
512→    detectIndentation,
513→    detectSemicolons,
514→    detectComponentStructure,
515→  ];
516→
517→  const results: Convention[] = [];
518→  for (const detector of detectors) {
519→    try {
520→      const result = await detector(projectRoot);
521→      if (result) results.push(result);
522→    } catch {
523→      // Skip failed detectors
524→    }
525→  }
526→
527→  return results;
528→}
529→
530→/**
531→ * Load existing conventions file
532→ */
533→export async function loadConventions(): Promise<ConventionsFile | null> {
534→  if (!(await fileExists(CONVENTIONS_PATH))) return null;
535→
536→  try {
537→    const content = await readFile(CONVENTIONS_PATH);
538→    return JSON.parse(content) as ConventionsFile;
539→  } catch {
540→    return null;
541→  }
542→}
543→
544→/**
545→ * Save conventions, preserving manual entries
546→ */
547→export async function saveConventions(
548→  detected: Convention[],
549→): Promise<ConventionsFile> {
550→  // Load existing to preserve manual entries
551→  const existing = await loadConventions();
552→  const manual = existing?.manual ?? {};
553→
554→  const detectedMap: Record<string, string> = {};
555→  for (const c of detected) {
556→    detectedMap[c.key] = c.value;
557→  }
558→
559→  const conventions: ConventionsFile = {
560→    detected: detectedMap,
561→    manual,
562→    detectedAt: new Date().toISOString(),
563→  };
564→
565→  await ensureDir(".sequant");
566→  await writeFile(CONVENTIONS_PATH, JSON.stringify(conventions, null, 2));
567→  return conventions;
568→}
569→
570→/**
571→ * Get merged conventions (manual overrides detected)
572→ */
573→export function getMergedConventions(
574→  file: ConventionsFile,
575→): Record<string, string> {
576→  return { ...file.detected, ...file.manual };
577→}
578→
579→/**
580→ * Format conventions for display
581→ */
582→export function formatConventions(file: ConventionsFile): string {
583→  const lines: string[] = [];
584→
585→  lines.push("Detected conventions:");
586→  const detected = Object.entries(file.detected);
587→  if (detected.length === 0) {
588→    lines.push("  (none)");
589→  } else {
590→    for (const [key, value] of detected) {
591→      lines.push(`  ${key}: ${value}`);
592→    }
593→  }
594→
595→  const manual = Object.entries(file.manual);
596→  if (manual.length > 0) {
597→    lines.push("");
598→    lines.push("Manual overrides:");
599→    for (const [key, value] of manual) {
600→      lines.push(`  ${key}: ${value}`);
601→    }
602→  }
603→
604→  lines.push("");
605→  lines.push(`Last detected: ${file.detectedAt}`);
606→
607→  return lines.join("\n");
608→}
609→
610→/**
611→ * Detect and save conventions in one call
612→ */
613→export async function detectAndSaveConventions(
614→  projectRoot: string,
615→): Promise<ConventionsFile> {
616→  const conventions = await detectConventions(projectRoot);
617→  return saveConventions(conventions);
618→}
619→
620→/**
621→ * Format conventions as context for AI skills
622→ */
623→export function formatConventionsForContext(file: ConventionsFile): string {
624→  const merged = getMergedConventions(file);
625→  const entries = Object.entries(merged);
626→
627→  if (entries.length === 0) return "";
628→
629→  const lines = ["## Codebase Conventions", ""];
630→  for (const [key, value] of entries) {
631→    lines.push(`- **${key}**: ${value}`);
632→  }
633→
634→  return lines.join("\n");
635→}
